// Worked focus: cmem-abi-layout-call-contract — Characterize calling convention, symbol visibility, integer widths, alignment, layout, and compiler flags for each supported ABI.
/* Evidence: cmem-worked-cmem-abi-ffi-shared-boundaries-5 */
/* Browser practice: PicoC 3.2.2 C89/C90 plus selected C99. */
/* Changed case 6090; native C23 claims require explicit transfer gates. */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>


struct ffi_buffer { unsigned abi_version; size_t length; size_t capacity; unsigned allocator_id; };

static int worked_cmem_abi_ffi_shared_boundaries_5(const struct ffi_buffer *buffer, unsigned expected_allocator) {
  if (buffer == NULL || buffer->abi_version != 1u) return 0;
  if (buffer->length > buffer->capacity) return 0;
  if (buffer->allocator_id != expected_allocator) return 0;
  return (int)buffer->length;
}

int main(void) {
  struct ffi_buffer buffer = { 1u, 4u, 8u, 7u };
  int wrong_heap = worked_cmem_abi_ffi_shared_boundaries_5(&buffer, 8u);
  int accepted = worked_cmem_abi_ffi_shared_boundaries_5(&buffer, 7u);
  int invariant = !wrong_heap && accepted == 4;
  printf("ffi length=%d invariant=%d\n", accepted, invariant);
  return invariant ? 0 : 1;
}

